window.bookSummaryJSON = "<p>From <i>New York Times </i>best-selling author Melissa Foster comes a new sexy romance, <i>Whisper of Love</i>, in which Tempest Braden, a music therapist, meets Nash Morgan, a reclusive artist, and single father, with a secret past. </p> <p>The Bradens are a series of stand-alone romances that may also be enjoyed as part of the larger Love in Bloom series. </p>"; 
